SELECT course_id, sec_id, semeber, year, building, room_number, capacity
FROM section NATURAL JOIN classroom
WHERE semester = 'Fall' AND year = 2017;

SELECT st.name AS student_name, st.dept_name as student_major, co.title AS course_title, co.dept_name as course_dept
FROM student AS st, course AS co
WHERE st.dept_name = co.dept_name;

SELECT * 
FROM takes 
WHERE grade = 'A' or grade = 'B';

SELECT student.id, student.name student_name, instructor.name instructor_name 
FROM student JOIN instructor ON student.id = instructor.id 
WHERE student.name != instructor.name;

SELECT course_id, sec_id FROM section WHERE semester = 'Fall' AND year = 2017
EXCEPT
SELECT course_id, sec_id FROM section WHERE semester = 'Spring' AND year = 2018;

SELECT name, dept_name, salary, budget 
FROM instructor NATURAL JOIN department 
WHERE salary > department.budget;

SELECT DISTINCT name
FROM instructor NATURAL JOIN teaches
WHERE semester = 'Spring' AND year = 2018;

SELECT DISTINCT t1.id, t1.course_id, t1.grade
FROM takes AS t1 JOIN takes AS t2 ON t1.id = t2.id and t1.course_id = t2.course_id
WHERE t1.semester != t2.semester or t1.year != t2.year or t1.sec_id != t2.sec_id;

SELECT dept_name FROM department
EXCEPT
SELECT dept_name FROM course;

SELECT course_id FROM teaches WHERE semester = 'Fall' AND year = 2017
UNION
SELECT course_id FROM teaches WHERE semester = 'Spring' AND year = 2018;

SELECT c.title AS course_title, p.title AS prerequisite_title 
FROM course c NATURAL JOIN prereq AS pr 
JOIN course AS p ON pr.prereq_id = p.course_id;

SELECT course_id FROM teaches WHERE semester = 'Fall' AND year = 2017
INTERSECT
SELECT course_id FROM teaches WHERE semester = 'Spring' AND year = 2018;
